def molecule_to_binary(molecule: str) -> str:
    atomic_weights = {
        'H': 1,
        'C': 12,
        'O': 16,
        # Add more elements as needed...
    }

    binary_code = ''
    i = 0
    while i < len(molecule):
        if molecule[i].isdigit():
            count = int(molecule[i])
            element = molecule[i+1]
            while i + 1 < len(molecule) and molecule[i+1].isdigit():
                count *= 10
                try:
                    count += int(molecule[i+1])
                except ValueError:
                    break
                i += 1
            if element in atomic_weights:
                binary_code += bin(atomic_weights[element])[2:] * count
            else:
                raise ValueError(f"Invalid molecule: {molecule}")
        elif molecule[i].isalpha():
            if i + 1 < len(molecule) and molecule[i+1].isdigit():
                count = int(molecule[i:i+2])
                element = molecule[i]
                i += 2
            else:
                count = 1
                element = molecule[i]
                i += 1

            binary_code += bin(atomic_weights[element])[2:] * count

        i += 1

    return '0b' + binary_code
